mapper.select:
SELECT CASE WHEN EXISTS (
    SELECT 1
    FROM u_user
    WHERE student_id = #{studentId}
      AND is_deleted = false
) THEN 1 ELSE 0 END

SELECT id AS userId, student_id AS studentId, COALESCE(nickname, student_id) AS nickname, CASE role WHEN 1 THEN 'ADMIN' ELSE 'USER' END AS role, CASE status WHEN 2 THEN 'BANNED' WHEN 1 THEN 'PENDING_VERIFICATION' ELSE 'NORMAL' END AS status, credit_score AS creditScore FROM u_user WHERE is_deleted = false
AND role = #{role}
AND ( CAST(id AS TEXT) = #{keyword} OR student_id ILIKE CONCAT('%', #{keyword}, '%') OR nickname ILIKE CONCAT('%', #{keyword}, '%') OR real_name ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY role DESC, update_time DESC, id DESC LIMIT #{limit}
